<?php declare(strict_types=1); $title = 'Foglalás – A Bata'; require __DIR__ . '/_layout_start.php'; $e = static fn (mixed $v): string => htmlspecialchars((string) $v, ENT_QUOTES | ENT_SUBSTITUTE, 'UTF-8'); ?>
<article class="admin-page detail" aria-labelledby="detail-title"><p><a href="/admin/bookings">← Vissza a listához</a></p><p class="eyebrow">Foglalás</p><h1 id="detail-title"><?= $e($booking['reference']) ?></h1><p><span class="status status-<?= $e($booking['status']) ?>"><?= $e($booking['status']) ?></span></p>
<section><h2>Vendég és időszak</h2><dl class="facts"><?php foreach (['contact_name'=>'Kapcsolattartó','email'=>'E-mail','phone'=>'Telefon','arrival_date'=>'Érkezés','departure_date'=>'Távozás','nights'=>'Éjszakák','adults'=>'Felnőttek','children'=>'Gyermekek','notes'=>'Megjegyzés','privacy_accepted_at'=>'Adatkezelés elfogadva','created_at'=>'Létrehozva','updated_at'=>'Frissítve'] as $key=>$label): ?><div><dt><?= $label ?></dt><dd><?= $e($booking[$key] ?? '—') ?></dd></div><?php endforeach ?><div><dt>Gyermekéletkorok</dt><dd><?= $e(implode(', ', $booking['children_ages'] ?? [])) ?: '—' ?></dd></div></dl></section>
<section><h2>Ár-pillanatkép</h2><p class="total"><?= $e($booking['total_amount']) ?> <?= $e($booking['currency']) ?></p><?php $snapshot=$booking['pricing_snapshot'] ?? []; ?><dl class="facts"><?php foreach (['pricing_base'=>'Árképzési alap','nights'=>'Éjszakák','persons'=>'Személyek','unit_price'=>'Egységár'] as $key=>$label): if (isset($snapshot[$key])): ?><div><dt><?= $label ?></dt><dd><?= $e(is_array($snapshot[$key]) ? implode(', ', $snapshot[$key]) : $snapshot[$key]) ?></dd></div><?php endif; endforeach ?></dl></section>
<?php $allowed=['pending'=>['confirm'=>'Megerősítés','reject'=>'Elutasítás','invalidate'=>'Érvénytelenítés'],'confirmed'=>['cancel'=>'Lemondás','invalidate'=>'Érvénytelenítés']][$booking['status']] ?? []; if ($allowed): ?><section><h2>Műveletek</h2><div class="actions"><?php foreach ($allowed as $action=>$label): ?><form method="post" action="/admin/bookings/<?= rawurlencode((string)$booking['reference']) ?>/<?= $action ?>"><input type="hidden" name="_csrf" value="<?= $e($csrfToken) ?>"><label for="note-<?= $action ?>">Admin megjegyzés (opcionális)</label><textarea id="note-<?= $action ?>" name="admin_note" maxlength="500"></textarea><button class="<?= in_array($action,['reject','cancel','invalidate'],true)?'danger':'' ?>" type="submit"><?= $label ?></button></form><?php endforeach ?></div></section><?php endif ?>
<section><h2>Státusztörténet</h2><ol class="timeline"><?php foreach ($booking['status_history'] as $item): ?><li><strong><?= $e($item['old_status'] ?? 'létrehozás') ?> → <?= $e($item['status']) ?></strong><br><time><?= $e($item['created_at']) ?></time><?php if ($item['admin_note']): ?><p><?= $e($item['admin_note']) ?></p><?php endif ?></li><?php endforeach ?></ol></section>
<section><h2>E-mail állapot</h2><?php if (!$booking['email_outbox']): ?><p>Nincs e-mail rekord.</p><?php else: ?><ul><?php foreach ($booking['email_outbox'] as $mail): ?><li><?= $e($mail['type']) ?> — <strong><?= $e($mail['status']) ?></strong> (<?= (int)$mail['attempts'] ?> kísérlet)<?php if ($mail['status']==='failed'): ?> <span class="alert-inline">Küldés sikertelen</span><?php endif ?></li><?php endforeach ?></ul><?php if (in_array($booking['status'], ['confirmed','rejected','cancelled'], true) && array_filter($booking['email_outbox'], static fn (array $mail): bool => $mail['status'] === 'failed')): ?><form method="post" action="/admin/bookings/<?= rawurlencode((string)$booking['reference']) ?>/retry-email"><input type="hidden" name="_csrf" value="<?= $e($csrfToken) ?>"><button type="submit">Sikertelen státuszlevél újraküldése</button></form><?php endif; endif ?></section></article><?php require __DIR__ . '/_layout_end.php'; ?>
